// ROM tables for the AAC-LC ENCODE quantizer, a 1:1 transcription of the
// vendored Fraunhofer FDK reference aacEnc_rom.cpp. Generated by narrowing the
// genuine source literals with the exact macros the C compiler folds:
//
//   - FDKaacEnc_mTab_3_4 / quantTableQ / quantTableE are FIXP_QTD == FIXP_SGL
//     (int16) on the build platform: ARCH_PREFER_MULT_32x16 is active because
//     FDK_archdef.h:117-118 promotes __aarch64__ to __arm__ and :165-166 sets
//     __ARM_ARCH_8__, selecting the `__arm__ && __ARM_ARCH_8__` branch
//     (FDK_archdef.h:182-187). So QTC == FX_DBL2FXCONST_SGL (aacEnc_rom.h:149-150),
//     narrowing each Q1.31 hex literal to a Q1.15 int16 with round-half-up.
//   - FDKaacEnc_mTab_4_3Elc and FDKaacEnc_specExpMantTableCombElc are
//     unconditional FIXP_DBL (int32), folded via FL2FXCONST_DBL.
//   - FDKaacEnc_specExpTableComb is UCHAR (small ints).
//
// aacEnc_rom.cpp citations: mTab_3_4 :574, quantTableQ :707, quantTableE :713,
// mTab_4_3Elc :864, specExpMantTableCombElc :1122, specExpTableComb :1155.

// mantSize mirrors MANT_SIZE == 1<<MANT_DIGITS (aacEnc_rom.h:145-146).
const (
	mantDigits = 9
	mantSize   = 1 << mantDigits // 512
	mantMask   = mantSize - 1    // ~MANT_SIZE is &(mantSize-1) after the cast
)

